
import base64
import hashlib

def check_password(input_pass):
    stored_hash = "215f009f2a32dcf4922404f52933a685c2da3c7fd5be13376b96e1f7e94e16ec"
    input_hash = hashlib.sha256(input_pass.encode()).hexdigest()
    return stored_hash == input_hash

password = input("🔐 أدخل كلمة السر: ")
if not check_password(password):
    print("❌ كلمة السر خاطئة!")
    exit()


import marshal
import binascii

def decrypt_marshal(obfuscated):
    # فك التشويش
    chunks = obfuscated.split("|")
    reversed_chunks = [chunk[::-1] for chunk in chunks]
    hex_data = ''.join(reversed_chunks)
    
    # تحويل hex إلى bytes
    data_bytes = binascii.unhexlify(hex_data)
    
    # فك تشفير marshal
    try:
        code_obj = marshal.loads(data_bytes)
        return code_obj
    except Exception as e:
        print(f"خطأ: {e}")
        return None

